func (gs *GameServer) showHelp(user *User) {
	help := "Available commands:\n"
	help += "/help - Show this help message\n"
	
	if gs.hasPermission(user, RoleMod) {
		help += "/kick <username> - Kick a user (Moderator+)\n"
	}
	
	if gs.hasPermission(user, RoleAdmin) {
		help += "/ban <username> - Ban a user (Admin)\n"
		help += "/unban <username> - Unban a user (Admin)\n"
		help += "/giveitems <username> <item> - Give items to a user (Admin)\n"
		help += "/promote <username> <role> - Change user role (Admin)\n"
	}
	
	user.Conn.Write([]byte(help))
}

func (gs *GameServer) broadcastMessage(sender *User, message string) {
	gs.mu.RLock()
	defer gs.mu.RUnlock()
	
	formattedMsg := fmt.Sprintf("[%s]: %s\n", sender.Username, message)
	
	for _, user := range gs.users {
		if user.ID != sender.ID {
			user.Conn.Write([]byte(formattedMsg))
		}
	}
}

func (gs *GameServer) broadcastMessageFrom(sender *User, message string) {
	gs.mu.RLock()
	defer gs.mu.RUnlock()
	
	formattedMsg := fmt.Sprintf("[SERVER]: %s\n", message)
	
	for _, user := range gs.users {
		user.Conn.Write([]byte(formattedMsg))
	}
}

